const ALLOWED_ACTIONS = new Set(['list_projects','list_issues','create_issue','update_issue','delete_issue','search_issues','change_status','assign_issue','set_deadline','add_label','remove_label','add_comment','get_issue','bulk','stats','cross_project_search','list_comments','me','list_members','list_cycles','list_modules','list_notifications','list_activity','create_epic','subscribe_issue','unsubscribe_issue','list_subscribers','delete_comment','update_comment','chat','digest']);

