  if (!creatorId && issueId) {
    try {
      const iss = await this.helpers.httpRequest({ method: 'GET', url: `${src.plane_url}/api/v1/workspaces/${src.workspace_slug}/projects/${src.project_id}/issues/${issueId}/`, headers: { 'X-API-Key': src.plane_token, 'Content-Type': 'application/json' }, timeout: 10000, json: true });
      const cb = iss && iss.created_by;
      creatorId = String((cb && cb.id ? cb.id : cb) || '');
    } catch (_) { _verifyFailed = true; }
  }
