const action = src.action || 'chat';
const PATCH_ACTIONS = ['change_status','assign_issue','set_deadline','add_label','remove_label'];
const PRIO_RU = {urgent:'срочный',high:'высокий',medium:'средний',low:'низкий',none:'не задан'};
const STATE_RU_GROUP = {backlog:'Отложенные',unstarted:'Запланированные',started:'В работе',completed:'Готово',cancelled:'Отменено'};
function _stateRu(stD){ if(!stD) return '?'; const g = stD.group || ''; return STATE_RU_GROUP[g] || stD.name || '?'; }

const llm_text = src.llm_text || '';
const quick_replies = src.quick_replies || null;

const PASSTHROUGH_ACTIONS = new Set(['stats','cross_project_search','list_comments','me','list_members','list_cycles','list_modules','list_notifications','list_activity','create_epic','subscribe_issue','unsubscribe_issue','list_subscribers','delete_comment','update_comment']);
// Если действие уже обработано в Stats/CrossProject handler — input уже
// содержит финальный {response, action, data}. Не перетираем — пробрасываем.
if (PASSTHROUGH_ACTIONS.has(action) && input && (input.response || input.data || input.action === action)) {
  const out = {
    response: input.response || llm_text || 'Готово.',
    action: input.action || action,
    data: input.data || null
  };
  if (input.error) out.error = input.error;
  if (src.project_name_canonical && out.data && !out.data.project_name_canonical) {
    out.data.project_name_canonical = src.project_name_canonical;
  }
  if (quick_replies) out.quick_replies = quick_replies;
  if (input.plane_setup_required || src.plane_setup_required) out.plane_setup_required = true;
  return [{ json: out }];
}



function planeError(r) {
  if (!r || typeof r !== 'object') return null;
  if (r.error && typeof r.error === 'object') {
    const e = r.error;
    const status = e.status || (e.response && e.response.status) || e.httpCode;
    if (status === 429) return 'Plane перегружен запросами. Подожди 5-10 секунд и попробуй снова.';
    if (status === 401 || status === 403) return 'Plane: нет доступа (проверь API token в настройках).';
    if (status === 404) return 'Plane: задача или проект не найдены.';
    if (status === 400) return 'Plane: некорректные данные запроса.';
    if (status >= 500) return 'Plane: внутренняя ошибка сервера (' + status + ').';
    if (e.message) return String(e.message).split(String.fromCharCode(10))[0].slice(0, 200);
  }
  if (r.error && typeof r.error === 'string') return r.error.split(String.fromCharCode(10))[0].slice(0, 200);
  if (r.detail) return String(r.detail).slice(0, 200);
  return null;
}

function wrap(out) {
  out.data = out.data || {};
  if (src.project_name_canonical && !out.data.project_name_canonical) {
    out.data.project_name_canonical = src.project_name_canonical;
  }
  if (quick_replies && !out.quick_replies) {
    out.quick_replies = quick_replies;
  }
  if (src.plane_setup_required) out.plane_setup_required = true;
  return [{ json: out }];
}

if (action === 'chat' || src.llm_error) {
  return wrap({ response: llm_text || 'Готово.', action: 'chat', data: null });
}

function getResolveError() {
  if (action === 'update_issue') {
    try { return $('update: resolve issue_id').first().json._resolve_error || null; } catch(_) {}
  } else if (action === 'delete_issue') {
    try { return $('delete: resolve issue_id').first().json._resolve_error || null; } catch(_) {}
  }
  return null;
}
const resolveErr = getResolveError() || input._resolve_error || (function(){ try { return $('resolve: extended').first().json._resolve_error || null; } catch(_) {} return null; })();
if (resolveErr) {
  const dis = (input && input._disambiguation) ||
              (function(){ try { return $('update: resolve issue_id').first().json._disambiguation; } catch(_) {} })() ||
              (function(){ try { return $('delete: resolve issue_id').first().json._disambiguation; } catch(_) {} })() || (function(){ try { return $('resolve: extended').first().json._disambiguation; } catch(_) {} })();
  const out = { response: resolveErr, action, data: null, error: resolveErr };
  if (dis) out.disambiguation = dis;
  return wrap(out);
}

if (action === 'list_projects') {
  const projects = (input.api_result && input.api_result.projects) || src.projects || [];
  // R7.84: тексты синхронизированы с фронтом (SLASH_COMMANDS./projects)
  return wrap({
    response: projects.length === 0 ? 'У вас нет проектов.' : 'Показываю список всех проектов:',
    action,
    data: { projects: projects.map(p => ({ id: p.id, name: p.name, identifier: p.identifier })) }
  });
}

if (action === 'list_issues' || action === 'search_issues') {
  const err = planeError(input);
  if (err) return wrap({ response: 'Не удалось получить задачи: ' + err, action, data: null, error: err });
  let issues = Array.isArray(input) ? input : (input.results || []);
  const _statesMap = input._states_map || null;
  const _projectId = input._project_id || null;
  if (action === 'search_issues') {
    const q = String((src.params && src.params.query) || '').toLowerCase().trim();
    if (q) issues = issues.filter(i => String(i.name || '').toLowerCase().includes(q));
  }
  return wrap({
    response: llm_text + (issues.length === 0 ? '\n\nЗадач не найдено.' : ('\n\nНайдено: ' + issues.filter(function(x){var p=x&&x.parent;if(p&&typeof p==='object')p=p.id;return !(p||(x.parent_detail&&x.parent_detail.id));}).length + '.')),
    action,
    data: {
      project: src.project_name_canonical,
      states_map: _statesMap,
      project_id: _projectId,
      issues: issues.map(i => ({
        id: i.id, name: i.name, priority: i.priority,
        state: i.state, state_detail: i.state_detail,
        sequence_id: i.sequence_id, created_at: i.created_at,
        target_date: i.target_date, start_date: i.start_date,
        assignees: i.assignees, labels: i.labels, created_by: i.created_by,
        comments_count: i.comments_count,
        parent: i.parent, parent_detail: i.parent_detail, sub_issues_count: i.sub_issues_count,
        description_html: i.description_html
      }))
    }
  });
}

if (action === 'create_issue') {
  const err = planeError(input);
  if (err) return wrap({ response: 'Не удалось создать задачу: ' + err, action, data: null, error: err });
  // R7.90: Plane при POST /issues/ возвращает state (UUID), но НЕ state_detail.
  // Фронт без state_detail не показывает кнопку статуса на карточке.
  // Подтягиваем state из /states/ и матчим UUID → {id, name, group, color}.
  let stateDetail = input.state_detail || null;
  if (!stateDetail && input.state && src.plane_url && src.workspace_slug && src.project_id) {
    try {
      const sresp = await this.helpers.httpRequest({
        method: 'GET',
        url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + src.project_id + '/states/',
        headers: { 'X-API-Key': src.plane_token, 'Content-Type': 'application/json' },
        timeout: 8000, json: true
      });
      const slist = Array.isArray(sresp) ? sresp : (sresp.results || []);
      const found = slist.find(s => s.id === input.state);
      if (found) stateDetail = { id: found.id, name: found.name, group: found.group, color: found.color };
      // Если по UUID не нашли — берём backlog как дефолт (Plane создаёт там).
      if (!stateDetail) {
        const backlog = slist.find(s => String(s.group||'').toLowerCase() === 'backlog');
        if (backlog) stateDetail = { id: backlog.id, name: backlog.name, group: backlog.group, color: backlog.color };
      }
    } catch (_) { /* fall through — карточка покажется без статуса, не критично */ }
  }
  return wrap({
    response: llm_text + ' Задача создана: ' + input.name + '.',
    action,
    data: { issue: { id: input.id, name: input.name, sequence_id: input.sequence_id, priority: input.priority, state: input.state, state_detail: stateDetail, target_date: input.target_date, start_date: input.start_date, project: src.project_name_canonical } }
  });
}

if (action === 'update_issue') {
  const err = planeError(input);
  if (err) return wrap({ response: 'Не удалось обновить задачу: ' + err, action, data: null, error: err });
  // АУДИТ: Plane не вернул объект задачи — НЕ говорим «обновлена», просим проверить.
  if (!input || !input.id) return wrap({ response: 'Plane не подтвердил обновление задачи «' + (src.params.name || src.params.issue_name || '') + '» — проверь её и повтори запрос.', action, data: null, error: 'empty_patch_response' });
  return wrap({
    response: llm_text + ' Задача обновлена: ' + (input.name || src.params.name || src.params.issue_name) + '.',
    action,
    data: { issue: { id: input.id, name: input.name, sequence_id: input.sequence_id, priority: input.priority } }
  });
}

if (action === 'delete_issue') {
  const err = planeError(input);
  if (err) return wrap({ response: 'Не удалось удалить задачу: ' + err, action, data: null, error: err });
  return wrap({ response: llm_text + ' Задача удалена.', action, data: { deleted: { id: (function(){ try { return $('delete: resolve issue_id').first().json.issue_id || ''; } catch(e){ return ''; } })(), name: (function(){ try { return $('delete: resolve issue_id').first().json.issue_name_canonical || (src.params && src.params.issue_name) || ''; } catch(e){ return (src.params && src.params.issue_name) || ''; } })() } } });
}

if (action === 'get_issue') {
  const err = planeError(input);
  if (err) return wrap({ response: 'Не удалось получить задачу: ' + err, action, data: null, error: err });
  return wrap({
    response: 'Задача «' + input.name + '». '
       + 'Приоритет: ' + (PRIO_RU[String(input.priority||'none').toLowerCase()] || input.priority || 'не задан') + '. '
       + 'Статус: ' + _stateRu(input.state_detail) + '. '
       + (input.target_date ? 'Срок: ' + input.target_date + '. ' : '')
       + (input.start_date ? 'Начало: ' + input.start_date + '. ' : '')
       + (input.created_at ? 'Создана: ' + String(input.created_at).slice(0,10) + '. ' : '')
       + (input.description_html ? 'Описание: ' + String(input.description_html).replace(/<[^>]+>/g,'').slice(0,200) : ''),
    action,
    data: { issue: input }
  });
}

if (PATCH_ACTIONS.includes(action)) {
  const err = planeError(input);
  if (err) return wrap({ response: 'Не удалось обновить задачу: ' + err, action, data: null, error: err });
  // issue 4: для change_status подтягиваем state_detail нового статуса —
  // иначе карточка в чате остаётся со старым статусом.
  let _psd = input.state_detail || null;
  if (action === 'change_status' && input.state && !_psd) {
    try {
      const _sr = await this.helpers.httpRequest({ method: 'GET', url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + src.project_id + '/states/', headers: { 'X-API-Key': src.plane_token, 'Content-Type': 'application/json' }, timeout: 8000, json: true });
      const _sl = Array.isArray(_sr) ? _sr : (_sr.results || []);
      const _sf = _sl.find(s => s.id === input.state);
      if (_sf) _psd = { id: _sf.id, name: _sf.name, group: _sf.group, color: _sf.color };
    } catch (_) {}
  }
  // АУДИТ: GET /states/ упал — синтезируем state_detail из ЗАПРОШЕННОГО статуса,
  // чтобы карточка/доска не остались с null (после F5 падало в «Запланированные»).
  if (action === 'change_status' && !_psd) {
    const _gm = { todo: 'unstarted', unstarted: 'unstarted', backlog: 'backlog', in_progress: 'started', started: 'started', done: 'completed', completed: 'completed', cancelled: 'cancelled' };
    const _gg = _gm[String((src.params && src.params.state) || '').toLowerCase()] || null;
    if (_gg) _psd = { id: input.state || null, name: STATE_RU_GROUP[_gg] || _gg, group: _gg, color: null };
  }
  // АУДИТ: пустой ответ Plane = не подтверждено, не врём «обновлено».
  if (!input || !input.id) return wrap({ response: 'Plane не подтвердил изменение задачи «' + (src.params.issue_name || '') + '» — проверь её и повтори запрос.', action, data: null, error: 'empty_patch_response' });
  const labels = { change_status: 'Статус', assign_issue: 'Исполнители', set_deadline: 'Срок', add_label: 'Метки', remove_label: 'Метки' };
  return wrap({
    response: (labels[action] || 'Поле') + ' обновлено для «' + (input.name || src.params.issue_name) + '».',
    action,
    data: { issue: { id: input.id, name: input.name, sequence_id: input.sequence_id, priority: input.priority, state: input.state, state_detail: _psd, target_date: input.target_date, assignees: input.assignees, labels: input.labels } }
  });
}

if (action === 'add_comment') {
  const err = planeError(input);
  if (err) return wrap({ response: 'Не удалось добавить комментарий: ' + err, action, data: null, error: err });
  return wrap({
    response: 'Комментарий добавлен к «' + src.params.issue_name + '».',
    action,
    data: { comment: { id: input.id, comment_html: input.comment_html } }
  });
}

// HIGH-1: bulk — реальная итерация через helpers.httpRequest
if (action === 'bulk') {
  const subActions = (src.params && Array.isArray(src.params.actions)) ? src.params.actions : [];
  // АУДИТ: потолок 30 операций за раз — иначе таймауты воркфлоу/рейт-лимит Plane.
  const _bulkSkipped = Math.max(0, subActions.length - 30);
  const subList = subActions.slice(0, 30);
  if (!subActions.length) {
    return wrap({ response: 'Bulk: нет операций.', action: 'bulk', data: null });
  }
  const projectsCache = src.projects || [];
  const issuesByProject = {};
  function gcMatchProj(projects, wanted) {
    var arr = Array.isArray(projects) ? projects : [];
    var w = String(wanted == null ? '' : wanted).trim().toLowerCase();
    if (!w) return { project: null, ambiguous: false, candidates: [] };
    var nm = function (p) { return String((p && p.name) || '').trim().toLowerCase(); };
    var ex = arr.filter(function (p) { return nm(p) === w; });
    if (ex.length) return { project: ex[0], ambiguous: false, candidates: ex };
    var pre = arr.filter(function (p) { return nm(p).indexOf(w) === 0; });
    if (pre.length === 1) return { project: pre[0], ambiguous: false, candidates: pre };
    if (pre.length > 1) return { project: null, ambiguous: true, candidates: pre };
    var sub = arr.filter(function (p) { return nm(p).indexOf(w) !== -1; });
    if (sub.length === 1) return { project: sub[0], ambiguous: false, candidates: sub };
    if (sub.length > 1) return { project: null, ambiguous: true, candidates: sub };
    return { project: null, ambiguous: false, candidates: [] };
  }
  function findProjectId(projectName) {
    if (!projectName) return null;
    var _mp = gcMatchProj(projectsCache, projectName);
    return _mp.project ? _mp.project.id : null;
  }
  async function getIssues(projectId) {
    if (issuesByProject[projectId]) return issuesByProject[projectId];
    try {
      const r = await this.helpers.httpRequest({
        method: 'GET',
        url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projectId + '/issues/?per_page=1000&expand=state_detail',
        headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
        timeout: 15000, json: true
      });
      issuesByProject[projectId] = Array.isArray(r) ? r : (r.results || []);
      return issuesByProject[projectId];
    } catch (e) { issuesByProject[projectId] = []; return []; }
  }
  let statesCache = null;
  async function getStates(projectId) {
    if (statesCache && statesCache.projectId === projectId) return statesCache.list;
    try {
      const r = await this.helpers.httpRequest({
        method: 'GET',
        url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projectId + '/states/',
        headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
        timeout: 15000, json: true
      });
      const list = Array.isArray(r) ? r : (r.results || []);
      statesCache = { projectId, list };
      return list;
    } catch (e) { return []; }
  }

  const results = [];
  for (const sub of subList) {
    const subAct = sub.action;
    const p = sub.params || {};
    let projId = findProjectId(p.project_name);
    // АУДИТ-ФИКС (офис 48/49): в bulk юзер обычно НЕ называет проект («Переведи Альфа
    // и Бета в работу») → LLM не передаёт project_name → раньше ВСЕ подоперации падали
    // «project not found: undefined». Теперь ищем задачу по имени во всех проектах.
    if (!projId && subAct !== 'create_issue' && p.issue_name) {
      const _hits = [];
      for (const _pr of projectsCache) {
        const _iss = await getIssues.call(this, _pr.id);
        const _f = _iss.find(i => String(i.name || '').toLowerCase() === String(p.issue_name || '').toLowerCase());
        if (_f) _hits.push(_pr.id);
        if (_hits.length > 1) break;
      }
      if (_hits.length === 1) projId = _hits[0];
      else if (_hits.length > 1) { results.push({ action: subAct, ok: false, error: 'задача «' + p.issue_name + '» есть в нескольких проектах — укажи проект' }); continue; }
    }
    if (!projId) { results.push({ action: subAct, ok: false, error: (p.project_name ? ('проект не найден: ' + p.project_name) : ('задача «' + (p.issue_name || p.name || '') + '» не найдена ни в одном проекте')) }); continue; }
    try {
      if (subAct === 'create_issue') {
        const body = { name: p.name || 'Без названия', priority: p.priority || 'none' };
        if (p.target_date && /^\d{4}-\d{2}-\d{2}$/.test(p.target_date)) body.target_date = p.target_date;
        if (p.description) body.description_html = '<p>' + String(p.description).replace(/[<>&]/g, c => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c])) + '</p>';
        const r = await this.helpers.httpRequest({
          method: 'POST',
          url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projId + '/issues/',
          headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
          body: body, timeout: 15000, json: true
        });
        if (!r || !r.id) { results.push({ action: subAct, ok: false, error: planeError(r) || 'Plane вернул ответ без id (задача не создана)' }); delete issuesByProject[projId]; continue; }
        results.push({ action: subAct, ok: true, name: r.name, _issue: r });
        delete issuesByProject[projId];
      } else if (subAct === 'delete_issue' || subAct === 'change_status' || subAct === 'update_issue' || subAct === 'add_comment' || subAct === 'set_deadline') {
        const issues = await getIssues.call(this, projId);
        const found = issues.find(i => String(i.name || '').toLowerCase() === String(p.issue_name || '').toLowerCase());
        if (!found) { results.push({ action: subAct, ok: false, error: 'задача не найдена: ' + p.issue_name }); continue; }
        let _bulkIssue = found; let _bulkDeleted = null;
        if (subAct === 'delete_issue') {
          await this.helpers.httpRequest({
            method: 'DELETE',
            url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projId + '/issues/' + found.id + '/',
            headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
            timeout: 15000, json: true
          });
          delete issuesByProject[projId];
          _bulkDeleted = { id: found.id, name: found.name }; _bulkIssue = null;
        } else if (subAct === 'change_status') {
          const states = await getStates.call(this, projId);
          const ALIASES = {'todo':'unstarted','to do':'unstarted','to_do':'unstarted','in progress':'started','in_progress':'started','wip':'started','работа':'started','в работе':'started','done':'completed','completed':'completed','готово':'completed','cancelled':'cancelled','canceled':'cancelled','отменено':'cancelled','backlog':'backlog','отложено':'backlog','отложенные':'backlog'};
          const wantedRaw = String(p.state || '').toLowerCase().replace(/_/g, ' ');
          const wantedGroup = ALIASES[wantedRaw] || wantedRaw;
          const target = states.find(s => String(s.group||'').toLowerCase() === wantedGroup)
                      || states.find(s => String(s.name||'').toLowerCase() === wantedRaw);
          if (!target) { results.push({ action: subAct, ok: false, error: 'статус не найден: ' + p.state }); continue; }
          await this.helpers.httpRequest({
            method: 'PATCH',
            url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projId + '/issues/' + found.id + '/',
            headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
            body: { state: target.id }, timeout: 15000, json: true
          });
          delete issuesByProject[projId];
          _bulkIssue = Object.assign({}, found, { state: target.id, state_detail: { id: target.id, name: target.name, group: target.group, color: target.color } });
        } else if (subAct === 'set_deadline') {
          await this.helpers.httpRequest({
            method: 'PATCH',
            url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projId + '/issues/' + found.id + '/',
            headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
            body: { target_date: (p.target_date && /^\d{4}-\d{2}-\d{2}$/.test(p.target_date)) ? p.target_date : null }, timeout: 15000, json: true
          });
        } else if (subAct === 'update_issue') {
          const upd = {};
          if (p.name) upd.name = p.name;
          if (p.priority) upd.priority = p.priority;
          if (p.target_date) upd.target_date = p.target_date;
          if (p.description) upd.description_html = '<p>' + String(p.description).replace(/[<>&]/g, c => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c])) + '</p>';
          await this.helpers.httpRequest({
            method: 'PATCH',
            url: src.plane_url + '/api/v1/workspaces/' + src.workspace_slug + '/projects/' + projId + '/issues/' + found.id + '/',
            headers: {'X-API-Key': src.plane_token, 'Content-Type': 'application/json'},
            body: upd, timeout: 15000, json: true
          });
        } else if (subAct === 'add_comment') {
          await this.helpers.httpRequest({
            method: 'POST',
