  if (!issue) {
    return [{ json: { response: 'Задача не найдена: ' + params.issue_name, action: action, data: null, error: 'issue_not_found' } }];
  }
  // Текущий пользователь — нужен для subscribe/unsubscribe (POST/DELETE передаёт subscriber=user_id)
  let meId = null;
  try {
    const me = await this.helpers.httpRequest({
      method: 'GET', url: planeUrl + '/api/v1/users/me/',
      headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
