  } catch (_) {}

  const subUrl = planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + proj.id + '/issues/' + issue.id + '/issue-subscribers/';

  if (action === 'subscribe_issue') {
    if (!meId) {
      return [{ json: { response: 'Не удалось определить пользователя для подписки.', action: action, data: null, error: 'me_unknown' } }];
    }
    try {
      await this.helpers.httpRequest({
        method: 'POST', url: subUrl,
        headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
        body: { subscriber: meId }, timeout: 10000, json: true
      });
      return [{ json: { response: 'Подписан на «' + issue.name + '».', action: action, data: { subscribed: true, issue_id: issue.id, me_id: meId } } }];
    } catch (e) {
      const msg = String(e.message || e);
      // 400 = уже подписан — это успех
      if (msg.indexOf('400') !== -1 || msg.toLowerCase().indexOf('already') !== -1) {
        return [{ json: { response: 'Уже подписан на «' + issue.name + '».', action: action, data: { subscribed: true, issue_id: issue.id, me_id: meId } } }];
      }
      return [{ json: { response: 'Не удалось подписаться: ' + msg.slice(0, 120), action: action, data: null, error: 'subscribe_failed' } }];
    }
  }

  if (action === 'unsubscribe_issue') {
    if (!meId) {
      return [{ json: { response: 'Не удалось определить пользователя.', action: action, data: null, error: 'me_unknown' } }];
    }
    // Plane API: DELETE /issue-subscribers/{subscriber_id}/ или /issue-subscribers/?subscriber=<id>
    // Пробуем оба варианта
    const urls = [
      subUrl + meId + '/',
      subUrl + '?subscriber=' + meId
    ];
    for (const u of urls) {
      try {
        await this.helpers.httpRequest({
          method: 'DELETE', url: u,
          headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
          timeout: 10000, json: true
        });
        return [{ json: { response: 'Отписан от «' + issue.name + '».', action: action, data: { subscribed: false, issue_id: issue.id, me_id: meId } } }];
      } catch (_) { /* try next */ }
    }
    return [{ json: { response: 'Уже не подписан или не удалось отписаться.', action: action, data: { subscribed: false, issue_id: issue.id, me_id: meId } } }];
  }

  // list_subscribers
  try {
    const r = await this.helpers.httpRequest({
      method: 'GET', url: subUrl + '?expand=subscriber_detail',
      headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'},
      timeout: 10000, json: true
    });
    const list = Array.isArray(r) ? r : (r.results || []);
    const subscribers = list.map(s => {
      const u = (s.subscriber_detail && typeof s.subscriber_detail === 'object') ? s.subscriber_detail : null;
      return {
        id: (u && u.id) || s.subscriber || s.id,
        display_name: (u && (u.display_name || (u.first_name && u.last_name ? u.first_name+' '+u.last_name : u.first_name))) || s.display_name || '',
        email: (u && u.email) || s.email || '',
        avatar: (u && u.avatar) || s.avatar || ''
      };
    });
    return [{ json: {
      response: 'Подписчиков: ' + subscribers.length,
      action: action,
      data: { subscribers: subscribers, issue_id: issue.id, me_id: meId }
    } }];
  } catch (e) {
    return [{ json: { response: 'Не удалось загрузить подписчиков: ' + (e.message || e).slice(0,120), action: action, data: null, error: 'subscribers_fetch_failed' } }];
  }
}

