// === digest: 3 категории задач за сегодня (без LLM) ===
// R7.74: route'ится через output 'stats' с флагом src._digest_mode=1
// (Switch не умеет OR-conditions). Проверяем оба варианта.
if (action === 'digest' || src._digest_mode === 1 || src._digest_mode === '1') {
  try {
    const allProjectsD = (src.projects && src.projects.length) ? src.projects : await getProjects.call(this);
    const todayD = new Date(); todayD.setHours(0,0,0,0);
    const todayIsoD = new Date(Date.now() + 10800000).toISOString().slice(0,10);
    const createdList = [], closedList = [], overdueList = [];
    function minIssue(i, projName) {
      return { id: i.id, name: i.name, sequence_id: i.sequence_id,
        priority: i.priority, target_date: i.target_date, start_date: i.start_date,
        completed_at: i.completed_at,
        project: projName, state_detail: i.state_detail, parent: i.parent, parent_detail: i.parent_detail };
    }
    for (const p of allProjectsD) {
      let issues = [];
      try { issues = await getIssues.call(this, p.id); } catch (_) { issues = []; }
      for (const i of issues) {
        const createdAt = String(i.created_at || '').slice(0, 10);
        if (createdAt === todayIsoD) createdList.push(minIssue(i, p.name));
        const grp = (i.state_detail && i.state_detail.group) || '';
        // R7.89: «Закрытые сегодня» = ТОЛЬКО group=completed + completed_at
        // приходится на сегодня. completed_at — поле, которое Plane сам ставит
        // при переходе задачи в группу Готово и сбрасывает (в null) если задачу
        // вытащили обратно. Это точное событие смены статуса на Готово, а не
        // суррогат через updated_at (который пересчитывался на любой комментарий).
        // Cancelled (Отменено) больше не считаются «закрытыми за сегодня».
        if (grp === 'completed') {
          const completedAt = String(i.completed_at || '').slice(0, 10);
          if (completedAt === todayIsoD) closedList.push(minIssue(i, p.name));
        }
        const isActiveOverdue = (grp === 'backlog' || grp === 'unstarted' || grp === 'started');
        const targetIso = String(i.target_date || '').slice(0, 10);
        if (isActiveOverdue && targetIso && targetIso < todayIsoD) overdueList.push(minIssue(i, p.name));
      }
    }
    return [{ json: {
      response: 'Сводка за сегодня: создано ' + createdList.length + ', закрыто ' + closedList.length + ', просрочено ' + overdueList.length + '.',
      action: 'digest',
      data: { digest: {
        created_issues: createdList,
        closed_issues: closedList,
        overdue_issues: overdueList,
        created_today: createdList.length,
        closed_today: closedList.length,
        overdue: overdueList.length
      } }
    } }];
  } catch (e) {
    return [{ json: {
      response: 'Не удалось собрать дайджест: ' + (e && e.message ? e.message : String(e)),
      action: 'digest',
      data: { digest: { created_issues: [], closed_issues: [], overdue_issues: [], created_today: 0, closed_today: 0, overdue: 0 } },
      error: 'digest_failed'
    } }];
  }
}

const allProjects = (src.projects && src.projects.length) ? src.projects : await getProjects.call(this);
// R8.16: если после fallback allProjects всё ещё пуст — скорее всего
// невалидный API-токен (Plane вернул 401/403, n8n HTTP node проглотил
// body) или некорректный URL/slug. Возвращаем сообщение которое фронт
// R8.14-фильтр поймает и покажет «Команда недоступна. Настройте...».
if (!allProjects.length && (action === 'stats' || action === 'cross_project_search' || src._digest_mode === 1)) {
  return [{ json: {
    response: 'Команда недоступна. Настройте ваш аккаунт.',
    action: action,
    data: null,
    error: 'plane_unavailable',
    plane_setup_required: true
  } }];
}
const scope = params.scope || 'summary';
const requestedProject = params.project_name;
const filterProjects = requestedProject
  ? (function(){ var _m = gcMatchProj(allProjects, requestedProject); return _m.project ? [_m.project] : []; })()
  : allProjects;

let response = '';
let issuesAll = [];
for (const p of filterProjects) {
  const issues = await getIssues.call(this, p.id);
  issues.forEach(i => { i._project_name = p.name; });
  issuesAll = issuesAll.concat(issues);
}

// R8.55: проекты есть, но задач 0 — могло быть из-за НЕДОСТУПНОСТИ Plane
// (неверный URL/токен): getIssues глотает ошибку и возвращает []. Отличаем
// «реально пусто» от «не достучались» — пробным запросом задач. Бросает →
// Plane недоступен → дружелюбный ответ вместо «Задачи отсутствуют».
if (issuesAll.length === 0 && filterProjects.length > 0 && (action === 'stats' || action === 'cross_project_search')) {
  let _reachable = false;
  try {
    await this.helpers.httpRequest({ method: 'GET', url: planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + filterProjects[0].id + '/issues/?per_page=1', headers: {'X-API-Key': planeToken, 'Content-Type': 'application/json'}, timeout: 10000, json: true });
    _reachable = true;
  } catch (_) { _reachable = false; }
  if (!_reachable) {
    return [{ json: { response: 'Команда недоступна. Настройте ваш аккаунт.', action: action, data: null, error: 'plane_unavailable', plane_setup_required: true } }];
  }
}

const today = new Date(new Date(Date.now() + 10800000).toISOString().slice(0,10));

if (action === 'stats') {
  if (scope === 'overdue') {
    const overdue = issuesAll.filter(i => i.target_date && new Date(i.target_date) < today
      && (i.state_detail && i.state_detail.group !== 'completed' && i.state_detail.group !== 'cancelled'));
    result = overdue; // R8.105 (баг 54): карточки = просроченные, а не все задачи
    if (!overdue.length) {
      response = 'Просроченных задач нет.';
    } else {
      const lines = overdue.slice(0, 20).map(i => '• ' + i.name + ' (срок: ' + i.target_date + ', проект: ' + i._project_name + ')');
      response = 'Просрочено: ' + overdue.length + ' задач.' + NL + lines.join(NL) +
        (overdue.length > 20 ? NL + '...и ещё ' + (overdue.length - 20) : '');
    }
  } else if (scope === 'summary') {
    const total = issuesAll.filter(function(x){var p=x&&x.parent;if(p&&typeof p==='object')p=p.id;return !(p||(x.parent_detail&&x.parent_detail.id));}).length;
    const byGroup = {unstarted:0,started:0,completed:0,cancelled:0,backlog:0};
    issuesAll.forEach(i => {
      var _sp = i && i.parent; if (_sp && typeof _sp === 'object') _sp = _sp.id; if (_sp || (i.parent_detail && i.parent_detail.id)) return; const g = (i.state_detail && i.state_detail.group) || 'unstarted';
      byGroup[g] = (byGroup[g] || 0) + 1;
    });
    response = (filterProjects.length === 1 ? 'Проект «' + filterProjects[0].name + '»: ' : 'По всем проектам: ') +
      'всего ' + total + ' задач.' + NL +
      'Задачи: ' + (byGroup.unstarted + byGroup.backlog) + NL +
      'В работе: ' + byGroup.started + NL +
      'Готово: ' + byGroup.completed + NL +
      'Отменено: ' + byGroup.cancelled;
  } else if (scope === 'by_assignee') {
    // issue 12: резолвим UUID исполнителей в ИМЕНА через members и считаем задачи
    // конкретного человека из запроса (раньше показывались UUID + текст про issue_id).
    const q = String(params.assignee_query || '').toLowerCase().trim();
    const memberName = {};
    for (const _p of filterProjects) {
      try {
        const _mr = await this.helpers.httpRequest({ method: 'GET', url: planeUrl + '/api/v1/workspaces/' + slug + '/projects/' + _p.id + '/members/?expand=member', headers: { 'X-API-Key': planeToken, 'Content-Type': 'application/json' }, timeout: 8000, json: true });
        const _ml = Array.isArray(_mr) ? _mr : (_mr.results || []);
        _ml.forEach(m => { const mem = m.member || m; const id = mem.id || m.member_id || m.id; const nm = mem.display_name || ((mem.first_name || '') + ' ' + (mem.last_name || '')).trim() || mem.email; if (id && nm) memberName[id] = nm; });
      } catch (_) {}
    }
    const byAssignee = {};
    issuesAll.forEach(i => { (i.assignees || []).forEach(uid => { byAssignee[uid] = (byAssignee[uid] || 0) + 1; }); });
    if (q) {
      const matchUids = Object.keys(memberName).filter(uid => String(memberName[uid]).toLowerCase().includes(q));
      if (!matchUids.length) {
        response = 'Не нашёл исполнителя «' + params.assignee_query + '» среди участников проектов. Проверь имя.';
      } else {
        response = matchUids.map(uid => 'У «' + memberName[uid] + '»: ' + (byAssignee[uid] || 0) + ' задач.').join(NL);
      }
    } else {
      const top = Object.entries(byAssignee).sort((a,b) => b[1]-a[1]).slice(0, 15);
      if (!top.length) response = 'Не нашёл задач с назначенными исполнителями.';
      else response = 'Статистика по исполнителям (топ-' + top.length + '):' + NL +
        top.map(([uid, cnt]) => '• ' + (memberName[uid] || (uid.slice(0,8) + '…')) + ' — ' + cnt + ' задач').join(NL);
    }
  } else if (scope === 'my_workload') {
    const opened = issuesAll.filter(i => i.state_detail && (i.state_detail.group === 'unstarted' || i.state_detail.group === 'started' || i.state_detail.group === 'backlog'));
    response = 'Открытых задач (в работе и в очереди): ' + opened.length + '.' + NL +
      (opened.length > 0 ? 'Первые 10:' + NL +
        opened.slice(0,10).map(i => '• ' + i.name + ' (' + i._project_name + ')').join(NL) : '');
  } else {
    response = 'Неизвестный scope для stats: ' + scope;
  }
} else if (action === 'cross_project_search') {
  const q = String(params.query || '').toLowerCase().trim();
  const filter = params.filter || '';
  var result = issuesAll;
  if (q) result = result.filter(i => String(i.name || '').toLowerCase().includes(q));
  if (filter === 'overdue') {
    result = result.filter(i => i.target_date && new Date(i.target_date) < today);
  } else if (filter === 'urgent') {
    result = result.filter(i => String(i.priority || '').toLowerCase() === 'urgent');
  } else if (filter === 'today') {
    const todayIso = today.toISOString().slice(0,10);
    result = result.filter(i => i.target_date && String(i.target_date).slice(0,10) === todayIso);
  } else if (filter === 'mine' || filter === 'created') {
    // R8.08: Plane v0.27.1 Public API (X-Api-Key) НЕ имеет /users/me/ —
    // он только в app-API через session-cookie. Поэтому юзер один раз
    // сохраняет свой user UUID в настройках Plane (поле plane_user_id),
    // и мы его используем. Если поле пустое — просим заполнить.
    let meId = src.plane_user_id || (src.body && src.body.plane_user_id) || null;
    if (!meId) {
      return [{ json: {
        response: 'Команда недоступна. Настройте ваш аккаунт.',
        action: 'cross_project_search',
        data: null,
        error: 'user_id_not_set'
      } }];
    }
    if (filter === 'mine') {
      result = result.filter(i => Array.isArray(i.assignees) && i.assignees.indexOf(meId) !== -1);
    } else {
      // filter === 'created' — R8.06: универсальный getCreator на 3 варианта.
      // Plane API в разных эндпоинтах может вернуть: created_by как UUID-string,
      // как объект {id}, либо поле называется created_by_id. Поддерживаем все.
      function getCreatorId(i) {
        if (!i) return null;
        if (typeof i.created_by === 'string' && i.created_by) return i.created_by;
        if (i.created_by && typeof i.created_by === 'object' && i.created_by.id) return String(i.created_by.id);
        if (i.created_by_id) return String(i.created_by_id);
        return null;
      }
      const before = result.length;
      result = result.filter(i => {
        const cr = getCreatorId(i);
        return cr && String(cr) === String(meId);
      });
      // Нет созданных задач у юзера токена -> result пуст, общий блок ниже отдаёт EMPTY[filter]=«Вы не создавали задач.» без error. Ранний диагностический return (meId/creator) убран: другому юзеру должно приходить простое «Вы не создавали задач.».
    }
  } else if (filter === 'all') {
    // R8.00: явный filter='all' — все задачи без отбора.
    // Семантически то же что пустой filter, но даёт отдельный EMPTY/FOUND
    // («Задачи отсутствуют» / «Показываю все задачи»).
    /* result уже = issuesAll, ничего не делаем */
  }
  // R7.84: тексты ответов синхронизированы с фронтом (SLASH_COMMANDS).
  // EMPTY — когда найдено 0; FOUND — заголовок перед карточками (фронт
  // дальше отрисует их по data.issues).
  // R8.00: EMPTY/FOUND для трёх «мои/созданные/все» команд + старых today/overdue/urgent.
  const EMPTY = {
    today: 'Задачи с сегодняшним сроком выполнения отсутствуют.',
    overdue: 'Задачи с истёкшим сроком выполнения отсутствуют.',
    urgent: 'У вас нет задач с максимальным приоритетом.',
    mine: 'За вами нет закреплённых задач.',
    created: 'Вы не создавали задач.',
    all: 'Задачи отсутствуют.'
  };
  const FOUND = {
    today: 'Показываю задачи с сегодняшним сроком выполнения:',
    overdue: 'Показываю задачи с истёкшим сроком выполнения:',
    urgent: 'Показываю задачи с максимальным приоритетом:',
    mine: 'Показываю закреплённые за вами задачи:',
    created: 'Показываю задачи, которые вы создали:',
    all: 'Показываю все задачи:'
  };
  if (!result.length) {
    response = EMPTY[filter] || ('По запросу «' + (q || '(все)') + '»' + (filter ? ' с фильтром ' + filter : '') + ' ничего не нашлось.');
  } else if (FOUND[filter]) {
    response = FOUND[filter];
  } else if (q) {
    response = 'Найдено по запросу «' + q + '»: ' + result.filter(function(x){var p=x&&x.parent;if(p&&typeof p==='object')p=p.id;return !(p||(x.parent_detail&&x.parent_detail.id));}).length;
  } else {
    response = 'Показываю все ваши задачи по всем проектам:';
  }
}

// BUG-FIX #4: если статистика вернула пустой результат ('Просрочек нет',
// 'Задач не найдено'), НЕ подкладываем issues — иначе фронт рендерит
// все 50 задач хотя ответ говорит «нет».
const responseLow = String(response||'').toLowerCase();
const isEmptyResult = /\b(нет|не найден|не нашёл|не нашел|ничего|пуст)\b/.test(responseLow);
// BUG-FIX #5: использовать ФИЛЬТРОВАННЫЙ result для cross_project_search.
// Раньше выкладывали ВСЕ задачи (issuesAll) даже когда ответ говорил «нашёл 2 срочные».
let sourceForData = issuesAll;
try { if (typeof result !== 'undefined' && Array.isArray(result)) sourceForData = result; } catch(_) {}
const dataIssues = (isEmptyResult || !Array.isArray(sourceForData) || sourceForData.length === 0) ? null : sourceForData.slice(0, 50).map(i => ({ id: i.id, name: i.name, sequence_id: i.sequence_id, priority: i.priority, target_date: i.target_date, start_date: i.start_date, project: i._project_name, state_detail: i.state_detail, parent: i.parent, parent_detail: i.parent_detail }));
return [{ json: {
  response: response || 'Готово.',
  action: action,
  data: dataIssues ? { issues: dataIssues } : null
} }];
